-- init.sql
-- Converted PostgreSQL DDL from instnwnd.sql (SQL Server)
-- Notes:
--  - identity columns use GENERATED BY DEFAULT AS IDENTITY
--  - SQL Server types mapped to Postgres types (nvarchar->varchar, ntext->text, image->bytea, money->numeric(19,4), bit->boolean)
--  - Some SQL Server-specific commands (GO, SET DATEFORMAT, etc.) removed
--  - Procedures from the original script are omitted (left as comments)

CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- === Tables ===
CREATE TABLE "Employees" (
  "EmployeeID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "LastName" varchar(20) NOT NULL,
  "FirstName" varchar(10) NOT NULL,
  "Title" varchar(30),
  "TitleOfCourtesy" varchar(25),
  "BirthDate" timestamp without time zone,
  "HireDate" timestamp without time zone,
  "Address" varchar(60),
  "City" varchar(15),
  "Region" varchar(15),
  "PostalCode" varchar(10),
  "Country" varchar(15),
  "HomePhone" varchar(24),
  "Extension" varchar(4),
  "Photo" bytea,
  "Notes" text,
  "ReportsTo" integer,
  "PhotoPath" varchar(255),
  CONSTRAINT "PK_Employees" PRIMARY KEY ("EmployeeID"),
  CONSTRAINT "FK_Employees_Employees" FOREIGN KEY ("ReportsTo") REFERENCES "Employees" ("EmployeeID"),
  CONSTRAINT "CK_Birthdate" CHECK ("BirthDate" < CURRENT_TIMESTAMP)
);
CREATE INDEX "LastName" ON "Employees" ("LastName");
CREATE INDEX "PostalCode" ON "Employees" ("PostalCode");

CREATE TABLE "Categories" (
  "CategoryID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "CategoryName" varchar(15) NOT NULL,
  "Description" text,
  "Picture" bytea,
  CONSTRAINT "PK_Categories" PRIMARY KEY ("CategoryID")
);
CREATE INDEX "CategoryName" ON "Categories" ("CategoryName");

CREATE TABLE "Customers" (
  "CustomerID" char(5) NOT NULL,
  "CompanyName" varchar(40) NOT NULL,
  "ContactName" varchar(30),
  "ContactTitle" varchar(30),
  "Address" varchar(60),
  "City" varchar(15),
  "Region" varchar(15),
  "PostalCode" varchar(10),
  "Country" varchar(15),
  "Phone" varchar(24),
  "Fax" varchar(24),
  CONSTRAINT "PK_Customers" PRIMARY KEY ("CustomerID")
);
CREATE INDEX "City" ON "Customers" ("City");
CREATE INDEX "CompanyName" ON "Customers" ("CompanyName");
CREATE INDEX "PostalCode_Customers" ON "Customers" ("PostalCode");
CREATE INDEX "Region_Customers" ON "Customers" ("Region");

CREATE TABLE "Shippers" (
  "ShipperID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "CompanyName" varchar(40) NOT NULL,
  "Phone" varchar(24),
  CONSTRAINT "PK_Shippers" PRIMARY KEY ("ShipperID")
);

CREATE TABLE "Suppliers" (
  "SupplierID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "CompanyName" varchar(40) NOT NULL,
  "ContactName" varchar(30),
  "ContactTitle" varchar(30),
  "Address" varchar(60),
  "City" varchar(15),
  "Region" varchar(15),
  "PostalCode" varchar(10),
  "Country" varchar(15),
  "Phone" varchar(24),
  "Fax" varchar(24),
  "HomePage" text,
  CONSTRAINT "PK_Suppliers" PRIMARY KEY ("SupplierID")
);
CREATE INDEX "CompanyName_Suppliers" ON "Suppliers" ("CompanyName");
CREATE INDEX "PostalCode_Suppliers" ON "Suppliers" ("PostalCode");

CREATE TABLE "Orders" (
  "OrderID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "CustomerID" char(5),
  "EmployeeID" integer,
  "OrderDate" timestamp without time zone,
  "RequiredDate" timestamp without time zone,
  "ShippedDate" timestamp without time zone,
  "ShipVia" integer,
  "Freight" numeric(19,4) DEFAULT 0,
  "ShipName" varchar(40),
  "ShipAddress" varchar(60),
  "ShipCity" varchar(15),
  "ShipRegion" varchar(15),
  "ShipPostalCode" varchar(10),
  "ShipCountry" varchar(15),
  CONSTRAINT "PK_Orders" PRIMARY KEY ("OrderID"),
  CONSTRAINT "FK_Orders_Customers" FOREIGN KEY ("CustomerID") REFERENCES "Customers" ("CustomerID"),
  CONSTRAINT "FK_Orders_Employees" FOREIGN KEY ("EmployeeID") REFERENCES "Employees" ("EmployeeID"),
  CONSTRAINT "FK_Orders_Shippers" FOREIGN KEY ("ShipVia") REFERENCES "Shippers" ("ShipperID")
);
CREATE INDEX "CustomerID_Orders" ON "Orders" ("CustomerID");
CREATE INDEX "CustomersOrders" ON "Orders" ("CustomerID");
CREATE INDEX "EmployeeID_Orders" ON "Orders" ("EmployeeID");
CREATE INDEX "EmployeesOrders" ON "Orders" ("EmployeeID");
CREATE INDEX "OrderDate" ON "Orders" ("OrderDate");
CREATE INDEX "ShippedDate" ON "Orders" ("ShippedDate");
CREATE INDEX "ShipPostalCode" ON "Orders" ("ShipPostalCode");
CREATE INDEX "ShippersOrders" ON "Orders" ("ShipVia");

CREATE TABLE "Products" (
  "ProductID" integer GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "ProductName" varchar(40) NOT NULL,
  "SupplierID" integer,
  "CategoryID" integer,
  "QuantityPerUnit" varchar(20),
  "UnitPrice" numeric(19,4) DEFAULT 0,
  "UnitsInStock" smallint DEFAULT 0,
  "UnitsOnOrder" smallint DEFAULT 0,
  "ReorderLevel" smallint DEFAULT 0,
  "Discontinued" boolean NOT NULL DEFAULT false,
  CONSTRAINT "PK_Products" PRIMARY KEY ("ProductID"),
  CONSTRAINT "FK_Products_Categories" FOREIGN KEY ("CategoryID") REFERENCES "Categories" ("CategoryID"),
  CONSTRAINT "FK_Products_Suppliers" FOREIGN KEY ("SupplierID") REFERENCES "Suppliers" ("SupplierID"),
  CONSTRAINT "CK_Products_UnitPrice" CHECK ("UnitPrice" >= 0),
  CONSTRAINT "CK_ReorderLevel" CHECK ("ReorderLevel" >= 0),
  CONSTRAINT "CK_UnitsInStock" CHECK ("UnitsInStock" >= 0),
  CONSTRAINT "CK_UnitsOnOrder" CHECK ("UnitsOnOrder" >= 0)
);
CREATE INDEX "CategoryID_Products" ON "Products" ("CategoryID");
CREATE INDEX "CategoriesProducts" ON "Products" ("CategoryID");
CREATE INDEX "ProductName_Products" ON "Products" ("ProductName");
CREATE INDEX "SupplierID_Products" ON "Products" ("SupplierID");
CREATE INDEX "SuppliersProducts" ON "Products" ("SupplierID");

CREATE TABLE "Order Details" (
  "OrderID" integer NOT NULL,
  "ProductID" integer NOT NULL,
  "UnitPrice" numeric(19,4) NOT NULL DEFAULT 0,
  "Quantity" smallint NOT NULL DEFAULT 1,
  "Discount" real NOT NULL DEFAULT 0,
  CONSTRAINT "PK_Order_Details" PRIMARY KEY ("OrderID", "ProductID"),
  CONSTRAINT "FK_Order_Details_Orders" FOREIGN KEY ("OrderID") REFERENCES "Orders" ("OrderID"),
  CONSTRAINT "FK_Order_Details_Products" FOREIGN KEY ("ProductID") REFERENCES "Products" ("ProductID"),
  CONSTRAINT "CK_Discount" CHECK ("Discount" >= 0 AND "Discount" <= 1),
  CONSTRAINT "CK_Quantity" CHECK ("Quantity" > 0),
  CONSTRAINT "CK_UnitPrice" CHECK ("UnitPrice" >= 0)
);
CREATE INDEX "OrderID_OrderDetails" ON "Order Details" ("OrderID");
CREATE INDEX "OrdersOrder_Details" ON "Order Details" ("OrderID");
CREATE INDEX "ProductID_OrderDetails" ON "Order Details" ("ProductID");
CREATE INDEX "ProductsOrder_Details" ON "Order Details" ("ProductID");

-- === Additional Tables (added later in original script) ===

CREATE TABLE "CustomerDemographics" (
  "CustomerTypeID" char(10) NOT NULL,
  "CustomerDesc" text,
  CONSTRAINT "PK_CustomerDemographics" PRIMARY KEY ("CustomerTypeID")
);

CREATE TABLE "CustomerCustomerDemo" (
  "CustomerID" char(5) NOT NULL,
  "CustomerTypeID" char(10) NOT NULL,
  CONSTRAINT "PK_CustomerCustomerDemo" PRIMARY KEY ("CustomerID", "CustomerTypeID"),
  CONSTRAINT "FK_CustomerCustomerDemo" FOREIGN KEY ("CustomerTypeID") REFERENCES "CustomerDemographics" ("CustomerTypeID"),
  CONSTRAINT "FK_CustomerCustomerDemo_Customers" FOREIGN KEY ("CustomerID") REFERENCES "Customers" ("CustomerID")
);

CREATE TABLE "Region" (
  "RegionID" integer NOT NULL,
  "RegionDescription" char(50) NOT NULL,
  CONSTRAINT "PK_Region" PRIMARY KEY ("RegionID")
);

CREATE TABLE "Territories" (
  "TerritoryID" varchar(20) NOT NULL,
  "TerritoryDescription" char(50) NOT NULL,
  "RegionID" integer NOT NULL,
  CONSTRAINT "PK_Territories" PRIMARY KEY ("TerritoryID"),
  CONSTRAINT "FK_Territories_Region" FOREIGN KEY ("RegionID") REFERENCES "Region" ("RegionID")
);

CREATE TABLE "EmployeeTerritories" (
  "EmployeeID" integer NOT NULL,
  "TerritoryID" varchar(20) NOT NULL,
  CONSTRAINT "PK_EmployeeTerritories" PRIMARY KEY ("EmployeeID", "TerritoryID"),
  CONSTRAINT "FK_EmployeeTerritories_Employees" FOREIGN KEY ("EmployeeID") REFERENCES "Employees" ("EmployeeID"),
  CONSTRAINT "FK_EmployeeTerritories_Territories" FOREIGN KEY ("TerritoryID") REFERENCES "Territories" ("TerritoryID")
);

-- === Views ===

CREATE VIEW "Customer and Suppliers by City" AS
SELECT "City", "CompanyName", "ContactName", 'Customers' AS "Relationship"
FROM "Customers"
UNION
SELECT "City", "CompanyName", "ContactName", 'Suppliers'
FROM "Suppliers";

CREATE VIEW "Alphabetical list of products" AS
SELECT p.*, c."CategoryName"
FROM "Categories" c INNER JOIN "Products" p ON c."CategoryID" = p."CategoryID"
WHERE p."Discontinued" = false;

CREATE VIEW "Current Product List" AS
SELECT p."ProductID", p."ProductName"
FROM "Products" p
WHERE p."Discontinued" = false;

CREATE VIEW "Orders Qry" AS
SELECT o."OrderID", o."CustomerID", o."EmployeeID", o."OrderDate", o."RequiredDate",
  o."ShippedDate", o."ShipVia", o."Freight", o."ShipName", o."ShipAddress", o."ShipCity",
  o."ShipRegion", o."ShipPostalCode", o."ShipCountry",
  c."CompanyName", c."Address", c."City", c."Region", c."PostalCode", c."Country"
FROM "Customers" c INNER JOIN "Orders" o ON c."CustomerID" = o."CustomerID";

CREATE VIEW "Products Above Average Price" AS
SELECT p."ProductName", p."UnitPrice"
FROM "Products" p
WHERE p."UnitPrice" > (SELECT AVG("UnitPrice") FROM "Products");

CREATE VIEW "Products by Category" AS
SELECT c."CategoryName", p."ProductName", p."QuantityPerUnit", p."UnitsInStock", p."Discontinued"
FROM "Categories" c INNER JOIN "Products" p ON c."CategoryID" = p."CategoryID"
WHERE p."Discontinued" <> true;

CREATE VIEW "Quarterly Orders" AS
SELECT DISTINCT c."CustomerID", c."CompanyName", c."City", c."Country"
FROM "Customers" c RIGHT JOIN "Orders" o ON c."CustomerID" = o."CustomerID"
WHERE o."OrderDate" BETWEEN '19970101' AND '19971231';

CREATE VIEW "Invoices" AS
SELECT o."ShipName", o."ShipAddress", o."ShipCity", o."ShipRegion", o."ShipPostalCode",
  o."ShipCountry", o."CustomerID", c."CompanyName" AS "CustomerName", c."Address", c."City",
  c."Region", c."PostalCode", c."Country",
  (e."FirstName" || ' ' || e."LastName") AS "Salesperson",
  o."OrderID", o."OrderDate", o."RequiredDate", o."ShippedDate", s."CompanyName" AS "ShipperName",
  od."ProductID", p."ProductName", od."UnitPrice", od."Quantity",
  od."Discount",
  ROUND((od."UnitPrice" * od."Quantity" * (1 - od."Discount"))::numeric, 2) AS "ExtendedPrice",
  o."Freight"
FROM "Shippers" s
  INNER JOIN (
    "Products" p INNER JOIN (
      ("Employees" e
        INNER JOIN ("Customers" c INNER JOIN "Orders" o ON c."CustomerID" = o."CustomerID")
        ON e."EmployeeID" = o."EmployeeID")
      INNER JOIN "Order Details" od ON o."OrderID" = od."OrderID")
    ON p."ProductID" = od."ProductID")
  ON s."ShipperID" = o."ShipVia";

CREATE VIEW "Order Details Extended" AS
SELECT od."OrderID", od."ProductID", p."ProductName",
  od."UnitPrice", od."Quantity", od."Discount",
  ROUND((od."UnitPrice" * od."Quantity" * (1 - od."Discount"))::numeric, 2) AS "ExtendedPrice"
FROM "Products" p INNER JOIN "Order Details" od ON p."ProductID" = od."ProductID";

CREATE VIEW "Order Subtotals" AS
SELECT od."OrderID",
  SUM(ROUND((od."UnitPrice" * od."Quantity" * (1 - od."Discount"))::numeric, 2)) AS "Subtotal"
FROM "Order Details" od
GROUP BY od."OrderID";

CREATE VIEW "Product Sales for 1997" AS
SELECT c."CategoryName", p."ProductName",
  SUM(ROUND((od."UnitPrice" * od."Quantity" * (1 - od."Discount"))::numeric, 2)) AS "ProductSales"
FROM ("Categories" c INNER JOIN "Products" p ON c."CategoryID" = p."CategoryID")
  INNER JOIN ("Orders" o INNER JOIN "Order Details" od ON o."OrderID" = od."OrderID")
  ON p."ProductID" = od."ProductID"
WHERE o."ShippedDate" BETWEEN '19970101' AND '19971231'
GROUP BY c."CategoryName", p."ProductName";

CREATE VIEW "Category Sales for 1997" AS
SELECT ps."CategoryName", SUM(ps."ProductSales") AS "CategorySales"
FROM "Product Sales for 1997" ps
GROUP BY ps."CategoryName";

CREATE VIEW "Sales by Category" AS
SELECT c."CategoryID", c."CategoryName", p."ProductName",
  SUM(ode."ExtendedPrice") AS "ProductSales"
FROM "Categories" c
  INNER JOIN ("Products" p
    INNER JOIN ("Orders" o INNER JOIN "Order Details Extended" ode ON o."OrderID" = ode."OrderID")
    ON p."ProductID" = ode."ProductID")
  ON c."CategoryID" = p."CategoryID"
WHERE o."OrderDate" BETWEEN '19970101' AND '19971231'
GROUP BY c."CategoryID", c."CategoryName", p."ProductName";

CREATE VIEW "Sales Totals by Amount" AS
SELECT os."Subtotal" AS "SaleAmount", o."OrderID", c."CompanyName", o."ShippedDate"
FROM "Customers" c
  INNER JOIN ("Orders" o INNER JOIN "Order Subtotals" os ON o."OrderID" = os."OrderID")
  ON c."CustomerID" = o."CustomerID"
WHERE os."Subtotal" > 2500
  AND o."ShippedDate" BETWEEN '19970101' AND '19971231';

CREATE VIEW "Summary of Sales by Quarter" AS
SELECT o."ShippedDate", o."OrderID", os."Subtotal"
FROM "Orders" o INNER JOIN "Order Subtotals" os ON o."OrderID" = os."OrderID"
WHERE o."ShippedDate" IS NOT NULL;

CREATE VIEW "Summary of Sales by Year" AS
SELECT o."ShippedDate", o."OrderID", os."Subtotal"
FROM "Orders" o INNER JOIN "Order Subtotals" os ON o."OrderID" = os."OrderID"
WHERE o."ShippedDate" IS NOT NULL;

-- === Stored Procedures (converted to PL/pgSQL functions) ===

CREATE OR REPLACE FUNCTION "CustOrdersDetail"(p_OrderID integer)
RETURNS TABLE(
  "ProductName" varchar,
  "UnitPrice" numeric,
  "Quantity" smallint,
  "Discount" integer,
  "ExtendedPrice" numeric
) LANGUAGE sql AS $$
  SELECT
    p."ProductName",
    ROUND(od."UnitPrice", 2) AS "UnitPrice",
    od."Quantity",
    CAST(od."Discount" * 100 AS integer) AS "Discount",
    ROUND((od."Quantity" * (1 - od."Discount") * od."UnitPrice")::numeric, 2) AS "ExtendedPrice"
  FROM "Products" p, "Order Details" od
  WHERE od."ProductID" = p."ProductID"
    AND od."OrderID" = p_OrderID;
$$;

CREATE OR REPLACE FUNCTION "CustOrdersOrders"(p_CustomerID char)
RETURNS TABLE(
  "OrderID" integer,
  "OrderDate" timestamp,
  "RequiredDate" timestamp,
  "ShippedDate" timestamp
) LANGUAGE sql AS $$
  SELECT "OrderID", "OrderDate", "RequiredDate", "ShippedDate"
  FROM "Orders"
  WHERE "CustomerID" = p_CustomerID
  ORDER BY "OrderID";
$$;

CREATE OR REPLACE FUNCTION "CustOrderHist"(p_CustomerID char)
RETURNS TABLE(
  "ProductName" varchar,
  "Total" bigint
) LANGUAGE sql AS $$
  SELECT p."ProductName", SUM(od."Quantity") AS "Total"
  FROM "Products" p, "Order Details" od, "Orders" o, "Customers" c
  WHERE c."CustomerID" = p_CustomerID
    AND c."CustomerID" = o."CustomerID"
    AND o."OrderID" = od."OrderID"
    AND od."ProductID" = p."ProductID"
  GROUP BY p."ProductName";
$$;

CREATE OR REPLACE FUNCTION "SalesByCategory"(p_CategoryName varchar, p_OrdYear varchar DEFAULT '1998')
RETURNS TABLE(
  "ProductName" varchar,
  "TotalPurchase" numeric
) LANGUAGE plpgsql AS $$
BEGIN
  IF p_OrdYear NOT IN ('1996', '1997', '1998') THEN
    p_OrdYear := '1998';
  END IF;

  RETURN QUERY
  SELECT
    p."ProductName",
    ROUND(SUM((od."Quantity" * (1 - od."Discount") * od."UnitPrice")::numeric), 0) AS "TotalPurchase"
  FROM "Order Details" od, "Orders" o, "Products" p, "Categories" c
  WHERE od."OrderID" = o."OrderID"
    AND od."ProductID" = p."ProductID"
    AND p."CategoryID" = c."CategoryID"
    AND c."CategoryName" = p_CategoryName
    AND SUBSTRING(TO_CHAR(o."OrderDate", 'YYYY-MM-DD'), 1, 4) = p_OrdYear
  GROUP BY p."ProductName"
  ORDER BY p."ProductName";
END;
$$;

CREATE OR REPLACE FUNCTION "Ten Most Expensive Products"()
RETURNS TABLE(
  "TenMostExpensiveProducts" varchar,
  "UnitPrice" numeric
) LANGUAGE sql AS $$
  SELECT p."ProductName" AS "TenMostExpensiveProducts", p."UnitPrice"
  FROM "Products" p
  ORDER BY p."UnitPrice" DESC
  LIMIT 10;
$$;

CREATE OR REPLACE FUNCTION "Employee Sales by Country"(
  p_Beginning_Date timestamp,
  p_Ending_Date timestamp
)
RETURNS TABLE(
  "Country" varchar,
  "LastName" varchar,
  "FirstName" varchar,
  "ShippedDate" timestamp,
  "OrderID" integer,
  "SaleAmount" numeric
) LANGUAGE sql AS $$
  SELECT e."Country", e."LastName", e."FirstName", o."ShippedDate", o."OrderID", os."Subtotal" AS "SaleAmount"
  FROM "Employees" e
    INNER JOIN ("Orders" o INNER JOIN "Order Subtotals" os ON o."OrderID" = os."OrderID")
    ON e."EmployeeID" = o."EmployeeID"
  WHERE o."ShippedDate" BETWEEN p_Beginning_Date AND p_Ending_Date;
$$;

CREATE OR REPLACE FUNCTION "Sales by Year"(
  p_Beginning_Date timestamp,
  p_Ending_Date timestamp
)
RETURNS TABLE(
  "ShippedDate" timestamp,
  "OrderID" integer,
  "Subtotal" numeric,
  "Year" text
) LANGUAGE sql AS $$
  SELECT o."ShippedDate", o."OrderID", os."Subtotal", TO_CHAR(o."ShippedDate", 'YYYY') AS "Year"
  FROM "Orders" o INNER JOIN "Order Subtotals" os ON o."OrderID" = os."OrderID"
  WHERE o."ShippedDate" BETWEEN p_Beginning_Date AND p_Ending_Date;
$$;
